import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, PieChart, FileText, Zap } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  // --- 1. DATA PARSING (Strict Isolation) ---
  const parseHoldings = useCallback((data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("DATA_PARSING_ERROR", e);
      return [];
    }
  }, []);

  // --- 2. API ACTIONS ---
  const fetchHistory = async () => {
    try {
      const { data } = await api.get('/portfolio/history');
      setHistory(Array.isArray(data) ? data : []);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) {
      toast.error("DELETE_FAILED");
    }
  };

  const handleDownload = async (item) => {
    const toastId = toast.loading("SYNTHESIZING_PDF...");
    try {
      const { data } = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([data], { type: 'application/pdf' }));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
      toast.success("EXPORT_SUCCESS", { id: toastId });
    } catch (err) {
      toast.error("EXPORT_FAILED", { id: toastId });
    }
  };

  useEffect(() => {
    fetchHistory();
  }, []);

  if (loading) return <div style={styles.center}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h2 style={styles.title}><Archive size={20} color="var(--accent-primary)"/> STRATEGY_VAULT</h2>
        <span style={styles.badge}>{history.length} NODES_STORED</span>
      </header>

      {history.length === 0 ? (
        <div style={styles.empty}>NO_DATA_RECORDS_INITIALIZED</div>
      ) : (
        <div style={styles.list}>
          {history.map((item) => (
            <div key={item.id} style={styles.card}>
              <div style={styles.cardContent}>
                <div style={styles.meta}>
                  <span style={styles.date}><Calendar size={12}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={styles.risk}><ShieldCheck size={12}/> RISK_SCORE: {item.risk_score}</span>
                </div>
                
                <h3 style={styles.goalTitle}>{item.goal}</h3>

                {/* HOLDINGS SECTION */}
                <div style={styles.sectionBlock}>
                  <label style={styles.sectionLabel}><PieChart size={10}/> HOLDINGS</label>
                  <div style={styles.tickerGroup}>
                    {parseHoldings(item.holdings).map((t, i) => (
                      <span key={i} style={styles.ticker}>{t}</span>
                    ))}
                  </div>
                </div>
              </div>

              <div style={styles.actionColumn}>
                <button onClick={() => setSelectedItem(item)} style={styles.actionBtn} title="View Detailed Rationale"><Eye size={18}/></button>
                <button onClick={() => handleDownload(item)} style={styles.actionBtn} title="Export Report"><Download size={18}/></button>
                <button onClick={() => handleDelete(item.id)} style={styles.deleteBtn} title="Wipe Data"><Trash2 size={18}/></button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* MODAL FOR SUMMARY & RATIONALE */}
      {selectedItem && (
        <div style={styles.overlay} onClick={() => setSelectedItem(null)}>
          <div style={styles.modal} onClick={e => e.stopPropagation()}>
            <div style={styles.modalHeader}>
              <h4 style={styles.modalTitle}>STRATEGY_DEEP_DIVE // ID_{selectedItem.id}</h4>
              <button onClick={() => setSelectedItem(null)} style={styles.closeBtn}><X size={20}/></button>
            </div>
            
            <div style={styles.modalBody}>
              {/* SUMMARY ISOLATION */}
              <div style={styles.modalSection}>
                <h5 style={styles.modalLabel}><FileText size={14}/> STRATEGY_SUMMARY</h5>
                <p style={styles.modalText}>{selectedItem.summary}</p>
              </div>

              <div style={styles.divider} />

              {/* RATIONALE ISOLATION */}
              <div style={styles.modalSection}>
                <h5 style={styles.modalLabel}><Zap size={14}/> AGENTIC_RATIONALE</h5>
                <div style={styles.rationaleBox}>
                  {selectedItem.rationale}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: { padding: '2rem', maxWidth: '1000px', margin: '0 auto' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', borderBottom: '1px solid var(--surface-border)' },
  title: { fontSize: '1.2rem', color: 'var(--text-primary)', display: 'flex', alignItems: 'center', gap: '10px' },
  badge: { fontSize: '0.7rem', color: 'var(--text-muted)', fontFamily: 'monospace' },
